// src/pages/Schedule.js
import React, { useEffect, useState } from "react";
import axios from "axios";
import { Link } from "react-router-dom";
import { teamData } from "./src/teamData.js";

export default function Schedule() {
  const [games, setGames] = useState([]);
  const [loading, setLoading] = useState(true);
  const [date, setDate] = useState("20250917");

  const handleChange = (e) => {
    const selected = e.target.value.replace(/-/g, ""); // YYYY-MM-DD → YYYYMMDD
    setDate(selected);
  };

  useEffect(() => {
    axios
      .get(`http://localhost:5001/api/schedule?date=${date}`)
      .then((res) => {
        setGames(res.data);
        setLoading(false);
      })
      .catch((err) => {
        console.error(err);
        setLoading(false);
      });
  }, [date]);



  if (loading) return <div className="p-6">Loading...</div>;

  function getTeamIcon(year, teamName) {
    var teamID = 0;
    switch (teamName) {
      case '삼성':
        teamID = 1001;
        break;

      case '해태':
        teamID = 2001;
        break;

      case 'KIA':
        teamID = 2002;
        break;

      case '롯데':
        teamID = 3001;
        break;

      case '삼미':
        teamID = 4001;
        break;

      case '청보':
        teamID = 4002;
        break;

      case '태평양':
        teamID = 4003;
        break;

      case '현대':
        teamID = 4004;
        break;

      case 'MBC':
        teamID = 5001;
        break;

      case 'LG':
        teamID = 5002;
        break;

      case 'OB':
        teamID = 6001;
        break;

      case '두산':
        teamID = 6002;
        break;

      case '빙그레':
        teamID = 7001;
        break;

      case '한화':
        teamID = 7002;
        break;

      case '쌍방울':
        teamID = 8001;
        break;

      case 'SK':
        teamID = 9001;
        break;

      case 'SSG':
        teamID = 9002;
        break;

      case '우리':
      case '히어로즈':
      case '넥센':
      case '키움':
        teamID = 10001;
        break;

      case 'NC':
        teamID = 11001;
        break;

      case 'KT':
        teamID = 12001;
        break;

      default:
        break;
    }
    teamID = String(teamID);
    return teamID;
  };

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      {/* 메인 화면 버튼 */}
      <div className="mb-4">
        <Link
          to="/"
          className="px-4 py-2 bg-blue-600 text-white rounded-lg shadow hover:bg-blue-700 transition"
        >
          ⬅ 메인 화면으로
        </Link>
      </div>

      <h1 className="text-3xl font-bold text-center mb-6">📅 KBO 경기 일정</h1>

      <div className="overflow-x-auto">
        <input type="date" onChange={handleChange} className="border p-2 rounded mb-4" />

        <table className="min-w-full bg-white shadow-md rounded-lg overflow-hidden">
          <thead className="bg-gray-800 text-white">
            <tr>
              <th className="py-3 px-4 text-left">{games.date}</th>
              <th className="py-3 px-4 text-left">시간</th>
              <th className="py-3 px-4 text-left">구장</th>
              <th className="py-3 px-4 text-left">원정팀</th>
              <th className="py-3 px-4 text-left">스코어</th>
              <th className="py-3 px-4 text-left">홈팀</th>
            </tr>
          </thead>
          <tbody>
            {games.map((game, idx) => {
              return (
                <tr key={idx} className="border-b hover:bg-gray-100 transition">
                  {game.gameType == '정규경기' ?
                    <td className="py-3 px-4">{game.date}</td> :
                    <td className="py-3 py-4 text-xs whitespace-pre-wrap"><span>{game.date}<br/>{game.gameType}</span></td>
                  }
                  <td className="py-3 px-4">{game.gameTime}</td>
                  <td className="py-3 px-4">{game.stadium}</td>
                  <td className="py-3 px-4 flex items-center gap-2">
                    <span className="text-base">{game.awayTeamName}</span>
                    <img
                    src={`https://statiz.sporki.com/data/team/ci/${date.slice(0, 4)}/${getTeamIcon(date.slice(0, 4), game.awayTeamName)}.svg`}
                    alt={game.awayTeamName}
                    className="w-12 h-12"
                    />
                  </td>
                  <td className="py-3 px-4">
                    {game.gameState < 2 ?
                      <span>경기 전</span>:
                    game.gameState >= 4 ?
                      <span>취소된 경기입니다.</span> :
                    game.gameScore}
                  </td>
                  <td className="py-3 px-4 flex items-center gap-2">
                    <span className="text-base">{game.homeTeamName}</span>
                    <img
                    src={`https://statiz.sporki.com/data/team/ci/${date.slice(0, 4)}/${getTeamIcon(date.slice(0, 4), game.homeTeamName)}.svg`}
                    alt={game.homeTeamName}
                    className="w-12 h-12"
                    />
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}
